package com.example.mydairy_app.ui.navigation

import androidx.compose.runtime.Composable
import androidx.compose.ui.Modifier
import androidx.navigation.NavType
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import androidx.navigation.navArgument
import com.example.mydairy_app.feature.calendar.CalendarScreen
import com.example.mydairy_app.feature.detail.DetailScreen
import com.example.mydairy_app.feature.editor.EditorScreen
import com.example.mydairy_app.feature.home.HomeScreen
import com.example.mydairy_app.feature.settings.SettingsScreen
import com.example.mydairy_app.feature.tags.TagManagerScreen

@Composable
fun AppNavHost(modifier: Modifier = Modifier): Unit {
    val navController = rememberNavController()

    NavHost(
        navController = navController,
        startDestination = Screen.Home.route,
        modifier = modifier
    ) {
        composable(route = Screen.Home.route) {
            HomeScreen(
                onOpenEditor = { entryId ->
                    navController.navigate(Screen.Editor.createRoute(entryId))
                },
                onOpenDetail = { entryId ->
                    navController.navigate(Screen.Detail.createRoute(entryId))
                },
                onOpenCalendar = { navController.navigate(Screen.Calendar.route) },
                onOpenTags = { navController.navigate(Screen.TagManager.route) },
                onOpenSettings = { navController.navigate(Screen.Settings.route) }
            )
        }

        composable(
            route = Screen.Editor.route,
            arguments = listOf(
                navArgument(Screen.ARG_ENTRY_ID) {
                    type = NavType.LongType
                    nullable = true
                    defaultValue = null
                }
            )
        ) { backStackEntry ->
            val entryId = backStackEntry.arguments?.let { bundle ->
                if (bundle.containsKey(Screen.ARG_ENTRY_ID)) {
                    bundle.getLong(Screen.ARG_ENTRY_ID)
                } else {
                    null
                }
            }
            EditorScreen(
                entryId = entryId,
                onBack = { navController.popBackStack() }
            )
        }

        composable(
            route = Screen.Detail.route,
            arguments = listOf(
                navArgument(Screen.ARG_ENTRY_ID) {
                    type = NavType.LongType
                }
            )
        ) { backStackEntry ->
            val entryId = backStackEntry.arguments?.getLong(Screen.ARG_ENTRY_ID) ?: return@composable
            DetailScreen(
                entryId = entryId,
                onOpenEditor = { editableEntryId ->
                    navController.navigate(Screen.Editor.createRoute(editableEntryId))
                },
                onBack = { navController.popBackStack() }
            )
        }

        composable(route = Screen.Calendar.route) {
            CalendarScreen(onBack = { navController.popBackStack() })
        }

        composable(route = Screen.TagManager.route) {
            TagManagerScreen(onBack = { navController.popBackStack() })
        }

        composable(route = Screen.Settings.route) {
            SettingsScreen(onBack = { navController.popBackStack() })
        }
    }
}

package com.example.mydairy_app.ui.navigation

sealed class Screen(val route: String) {
    data object Home : Screen("home")
    data object Calendar : Screen("calendar")
    data object TagManager : Screen("tags")
    data object Settings : Screen("settings")
    data object Detail : Screen("detail/{entryId}") {
        fun createRoute(entryId: Long): String = "detail/$entryId"
    }

    data object Editor : Screen("editor?entryId={entryId}") {
        fun createRoute(entryId: Long?): String =
            if (entryId == null) {
                "editor"
            } else {
                "editor?entryId=$entryId"
            }
    }

    companion object {
        const val ARG_ENTRY_ID: String = "entryId"
    }
}

